sql:
SELECT model_name, model_year 
FROM car_models 
WHERE model_year = '2010';

SELECT model_name 
FROM car_models 
WHERE model_year = '1975';

SELECT cm.model_name, cm.model_year, m.manufacturer_name
FROM car_models cm
JOIN manufacturers m ON cm.manufacturer_id = m.manufacturer_id;

SELECT feature_description
FROM car_features
WHERE model_id = 2;

SELECT cm.model_name, dt.drive_type 
FROM car_models cm
JOIN drive_types dt ON cm.drive_type_id = dt.drive_id;

SELECT car_models.model_name, manufacturers.manufacturer_name
FROM car_models
INNER JOIN manufacturers ON car_models.manufacturer_id = manufacturers.manufacturer_id;

SELECT car_models.model_name
FROM car_models
WHERE car_models.model_year = (SELECT model_years.year_name FROM model_years WHERE model_years.year_id = 0);

SELECT COUNT(*) AS num_times_available
FROM car_features
WHERE feature_name = 'Leather Seats';

SELECT model_name 
FROM car_models 
WHERE model_id = 1;

SELECT model_name
FROM car_models
WHERE model_year = '2022' AND fuel_type = 'gasoline';
